    {
      "from_node": "PlaceOrder",
      "from_output": "message",
      "to_node": "parent",
      "to_input": "message",
      "note": "Return success/error message"
    },
    {
      "from_node": "CancelOrder",
      "from_output": "order_id",
      "to_node": "parent",
      "to_input": "order_id",
      "note": "Return order ID"
    },
