    {
      "from_node": "CancelOrder",
      "from_output": "message",
      "to_node": "parent",
      "to_input": "message",
      "note": "Return success/error message"
    },
    {
      "from_node": "TrackOrder",
      "from_output": "order_id",
      "to_node": "parent",
      "to_input": "order_id",
      "note": "Return order ID"
    },
    {
      "from_node": "TrackOrder",
      "from_output": "status",
      "to_node": "parent",
      "to_input": "status",
      "note": "Return order status"
    },
    {
      "from_node": "TrackOrder",
      "from_output": "message",
      "to_node": "parent",
      "to_input": "message",
      "note": "Return order details or error"
    }
  ],
  "interface_audit": {
    "identity_preservation_detail": "All four children from Stage 1 are preserved exactly: ParseCommand, PlaceOrder, CancelOrder, TrackOrder. No children were added, deleted, renamed, or reordered.",
    "semantic_preservation_detail": "All Stage 1 fields (purpose, behavior, boundary, preconditions, postconditions, guarantees, composition_role) remain unchanged. Only interface fields (call_inputs, internal_leaf_accesses, outputs, signature) were added.",
    "call_signature_detail": "Each signature contains only call_inputs parameters. ParseCommand takes 'input' from parent. PlaceOrder, CancelOrder, TrackOrder each take 'order_data' from ParseCommand output. No internal resources appear in signatures.",
    "internal_leaf_separation_detail": "Data stores (orders, inventory, payments) appear only in internal_leaf_accesses, not in call_inputs. This correctly separates parent-call parameters from internal resource access.",
    "dataflow_schema_detail": "All dataflow edges use legal endpoints: 'parent' or exact child names (ParseCommand, PlaceOrder, CancelOrder, TrackOrder). No resource names like orders, inventory, payments appear as from_node/to_node.",
    "final_status": "ok"
  }
}
